const normalizePhone = (p: string | undefined | null) => {
  let s = String(p || '').trim();
  if (s.includes('.')) s = s.split('.')[0];
  const clean = s.replace(/\D/g, '');
  return clean.length >= 9 ? clean.slice(-9) : clean;
};

// Interface for the data passed to computeHash
interface HashableRecord {
  id?: string;
  date: string;
  unitsSold: number;
  unitPrice: number;
  produceId?: string;
  orderId?: string;
  [key: string]: unknown; 
}

const computeHash = async (record: HashableRecord): Promise<string> => {
  const normalizedUnits = Number(record.unitsSold).toString();
  const normalizedPrice = Number(record.unitPrice).toString();
  
  // Integrity Check: Include produceId and orderId in the hash payload
  const pid = record.produceId || 'null';
  const oid = record.orderId || 'null';
  
  const msg = `${record.id || ''}|${record.date}|${normalizedUnits}|${normalizedPrice}|${pid}|${oid}`;
  
  const encoder = new TextEncoder();
  const data = encoder.encode(msg);
  const hashBuffer = await crypto.subtle.digest('SHA-256', data);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(b => b.toString(16).padStart(2, '0')).join('').substring(0, 12);
};

// Helper: Merge cloud data with local data, preserving local-only and unsynced records
const mergeData = <T extends { id: string, date?: string, createdAt?: string, synced?: boolean, buyingPrice?: number, isAggregate?: boolean }>(cloudItems: T[], localItems: T[]): T[] => {
  const cloudMap = new Map(cloudItems.map(i => [i.id, i]));
  const merged = [...cloudItems];
  
  localItems.forEach(localItem => {
    if (!cloudMap.has(localItem.id)) {
      merged.push(localItem);
    } else if (localItem.synced === false) {
      // Preserve local modifications that haven't been synced yet
      const index = merged.findIndex(i => i.id === localItem.id);
      if (index !== -1) {
        merged[index] = localItem;
      }
    } else {
      // Even if synced, preserve critical local fields if cloud dropped them due to missing schema!
      const index = merged.findIndex(i => i.id === localItem.id);
      if (index !== -1) {
        if (localItem.buyingPrice !== undefined && (!merged[index].buyingPrice || merged[index].buyingPrice === 0)) {
           merged[index].buyingPrice = localItem.buyingPrice;
        }
        if (localItem.isAggregate === true && !merged[index].isAggregate) {
           merged[index].isAggregate = localItem.isAggregate;
        }
      }
    }
  });

  return merged.sort((a, b) => {
    const dateA = a.date || a.createdAt || '';
    const dateB = b.date || b.createdAt || '';
    return dateB.localeCompare(dateA);
  });
};

